"""Модели запроса и результата OCR к Yandex Vision API."""from __future__ import annotationsfrom dataclasses import dataclass, fieldfrom pathlib import Pathfrom typing import Anyfrom src.core.utils.hash import md5_stringfrom ..module import DEFAULT_MODELDEFAULT_LANGUAGE: list[str] = ["ru", "en"]@dataclassclass YandexOCRRequest:    """Параметры распознавания: модель, языки, путь к изображению, хеш, опциональный путь к кешу."""    model: str = DEFAULT_MODEL    language: list[str] = field(default_factory=lambda: list(DEFAULT_LANGUAGE))    image_path: Path | str | None = None    image_hash: str | None = None    cache_path: Path | None = None    def get_request_hash(self) -> str:        """MD5 от строки: model + '-' + language через '-' + image_hash."""        lang_part = "-".join(self.language) if self.language else ""        combined = f"{self.model}-{lang_part}-{self.image_hash or ''}"        return md5_string(combined)@dataclassclass YandexOCRResult:    """Результат OCR по одному изображению: полный текст и сырой ответ API."""    full_text: str = ""    content_hash: str | None = None    result: dict[str, Any] = field(default_factory=dict)    #: True — ответ взят из файлового кеша, запроса к API не было.    from_cache: bool = False